mapper.select:
SELECT t.teacher_id, t.teacher_name, t.gender, t.title, d.department_name FROM teacher t LEFT JOIN department d ON t.department_id = d.department_id
AND t.teacher_name LIKE CONCAT('%', #{teacherName}, '%')
AND t.department_id = #{departmentId}
AND t.title = #{title}
ORDER BY t.teacher_id
